function isRetryWindowExpired(dateString: string | null): boolean {
  if (!dateString) return false;
  // Parse the server date (assumed ISO 8601/UTC) and compare using UTC timestamps
  // to ensure consistent behavior regardless of client timezone.
  // Retry window is 2 weeks (14 days) from batch creation.
  const createdAt = new Date(dateString);
  const now = new Date();

  // Both getTime() values are UTC milliseconds since epoch, making this comparison
  // timezone-safe. The 2 week threshold = 14 days × 24 hours × 60 min × 60 sec × 1000 ms
  const twoWeeksMs = 14 * 24 * 60 * 60 * 1000;
  return now.getTime() - createdAt.getTime() > twoWeeksMs;
}

function BatchPoller({
  batchRunId,
  listStatus,
  onStatusChange,
  onTerminal,
}: {
  batchRunId: string;
  listStatus: string;
  onStatusChange: () => void;
  onTerminal: (status: string) => void;
}) {
  const queryClient = useQueryClient();
  const { data } = useBatchRunStatus(batchRunId);
  const lastNotifiedStatus = useRef<string | null>(null);
  const status = data?.status?.toLowerCase();
  const normalizedListStatus = listStatus?.toLowerCase();

  useEffect(() => {
    if (!status || status === lastNotifiedStatus.current) {
      return;
    }

    lastNotifiedStatus.current = status;
    const terminal =
      status === "success" || status === "failed" || status === "completed" || status === "failure";

    if (terminal && data) {
      onTerminal(data.status);
      queryClient.invalidateQueries({ queryKey: ["batch", "status", batchRunId] });
      return;
    }

    if (status !== normalizedListStatus) {
      onStatusChange();
    }
  }, [status, normalizedListStatus, data, onTerminal, onStatusChange, queryClient, batchRunId]);

  return null;
}

